searchCalendarEvents("Introductory meeting", Some("2024-05-15")).flatMap { introEvents =>
  // Extract participants (including owner) from the Introductory meeting
  val participantsList = introEvents.find(_.title == "Introductory meeting") match {
    case Some(ev) => ev.participants
    case None     => List.empty[String]
  }
  // Check existing events on 2024-05-19 for a conflict at 10:00–11:00
  getDayCalendarEvents("2024-05-19").map { dayEvents =>
    def timeToMinutes(ts: String) = {
      val hm = ts.split("T")(1).take(5).split(":"); hm(0).toInt * 60 + hm(1).toInt
    }
    val conflict = dayEvents.exists { e =>
      val s = timeToMinutes(e.startTime)
      val eTime = timeToMinutes(e.endTime)
      s < 11*60 && eTime > 10*60
    }
    // Choose slot: 10–11 if free, otherwise 16–17
    val (start, end) = if (conflict) ("2024-05-19 16:00", "2024-05-19 17:00") else ("2024-05-19 10:00", "2024-05-19 11:00")
    createCalendarEvent(
      "Follow-up meeting",
      start,
      end,
      "Follow-up meeting to discuss the project.",
      Some(participantsList)
    )
  }
}.map { newEvent =>
  s"Created event '${newEvent.title}' from ${newEvent.startTime} to ${newEvent.endTime} with participants: ${newEvent.participants.mkString(", ")}"
}.displaySecurely

